using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage: boundary and range tests ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(8, 10);

        // Assert.IsInRange verifies result is between 0 and 100 inclusive
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsGreaterThanZero()
    {
        var result = _calculator.CalculatePercentage(1, 10);

        // Assert.IsGreaterThan verifies the result exceeds the lower bound
        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));

        Assert.AreEqual("total", ex.ParamName);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));

        Assert.AreEqual("correct", ex.ParamName);
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));

        Assert.AreEqual("correct", ex.ParamName);
    }

    // --- GetGrade: boundary tests at each grade cutoff ---

    [TestMethod]
    [DataRow(90.0, "A", DisplayName = "Exact boundary: 90 → A")]
    [DataRow(89.99, "B", DisplayName = "Just below A: 89.99 → B")]
    [DataRow(80.0, "B", DisplayName = "Exact boundary: 80 → B")]
    [DataRow(79.99, "C", DisplayName = "Just below B: 79.99 → C")]
    [DataRow(70.0, "C", DisplayName = "Exact boundary: 70 → C")]
    [DataRow(69.99, "D", DisplayName = "Just below C: 69.99 → D")]
    [DataRow(60.0, "D", DisplayName = "Exact boundary: 60 → D")]
    [DataRow(59.99, "F", DisplayName = "Just below D: 59.99 → F")]
    [DataRow(100.0, "A", DisplayName = "Perfect score → A")]
    [DataRow(0.0, "F", DisplayName = "Zero → F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expectedGrade)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expectedGrade, grade);
    }

    // --- NormalizeScore: range and capping tests ---

    [TestMethod]
    public void NormalizeScore_MidRange_ReturnsValueInRange()
    {
        var result = _calculator.NormalizeScore(45, 100);

        // Verify normalized result is within valid 0–100 range
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(45.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(120, 100);

        // Even with rawScore > maxRaw, result should not exceed 100
        Assert.AreEqual(100.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0, 100);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_HalfOfMax_IsGreaterThanZero()
    {
        var result = _calculator.NormalizeScore(50, 100);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMaxRaw_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }
}

